from __future__ import annotations
import base64
from pathlib import Path
ROOT = Path(__file__).resolve().parents[1]
CHARTS = ROOT / 'results' / 'charts'
OUT = ROOT / 'report.html'

def b64(path: Path) -> str:
    return base64.b64encode(path.read_bytes()).decode('ascii')

def img(path: Path, alt: str) -> str:
    return f'<img src="data:image/png;base64,{b64(path)}" alt="{alt}" />'
HTML = '<!DOCTYPE html>\n<html lang="en">\n<head>\n<meta charset="utf-8">\n<meta name="viewport" content="width=device-width, initial-scale=1">\n<title>hf-sandbox vs E2B — Scalability Comparison</title>\n<style>\n  :root {\n    --bg: #0e1116; --panel: #161b22; --panel2: #1e242c; --border: #2c333d;\n    --text: #d7dadf; --muted: #8a9099; --accent: #59a6ff;\n    --pass: #3ec97a; --warn: #e6b455; --fail: #e25c5c;\n  }\n  * { box-sizing: border-box; }\n  html, body { margin: 0; padding: 0; background: var(--bg); color: var(--text);\n               font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, system-ui, sans-serif;\n               font-size: 15px; line-height: 1.6; }\n  .wrap { max-width: 980px; margin: 0 auto; padding: 36px 28px 80px; }\n  h1 { font-size: 26px; margin: 0 0 4px; color: #fff; letter-spacing: -0.01em; }\n  .meta { color: var(--muted); font-size: 13px; margin-bottom: 32px;\n          padding-bottom: 16px; border-bottom: 1px solid var(--border); }\n  h2 { font-size: 20px; margin: 36px 0 12px; color: #fff;\n       padding-top: 14px; border-top: 1px solid var(--border); }\n  h3 { font-size: 16px; margin: 24px 0 8px; color: var(--accent); }\n  p { margin: 10px 0; }\n  a { color: var(--accent); text-decoration: none; }\n  a:hover { text-decoration: underline; }\n  code { background: var(--panel2); padding: 2px 6px; border-radius: 4px;\n         font-family: ui-monospace, SF Mono, Menlo, monospace; font-size: 13px;\n         color: #ffb37a; }\n  pre { background: var(--panel); padding: 14px 16px; border-radius: 6px;\n        border: 1px solid var(--border); overflow-x: auto;\n        font-family: ui-monospace, SF Mono, Menlo, monospace;\n        font-size: 13px; line-height: 1.55; }\n  pre code { background: transparent; padding: 0; color: var(--text); }\n  table { border-collapse: collapse; width: 100%; margin: 14px 0;\n          background: var(--panel); border-radius: 6px; overflow: hidden;\n          border: 1px solid var(--border); }\n  th, td { padding: 8px 12px; text-align: left; border-bottom: 1px solid var(--border);\n           font-size: 13.5px; }\n  th { background: var(--panel2); color: var(--muted); font-weight: 600;\n       text-transform: uppercase; font-size: 11px; letter-spacing: 0.5px; }\n  tr:last-child td { border-bottom: 0; }\n  td.pass { color: var(--pass); font-weight: 600; }\n  td.fail { color: var(--fail); font-weight: 600; }\n  td.warn { color: var(--warn); font-weight: 600; }\n  strong { color: #fff; }\n  blockquote { border-left: 3px solid var(--accent); margin: 14px 0;\n               padding: 8px 16px; background: var(--panel); color: var(--text); }\n  img { max-width: 100%; height: auto; display: block; margin: 18px auto;\n        border-radius: 6px; border: 1px solid var(--border); background: #fff; }\n  ul, ol { padding-left: 22px; }\n  li { margin: 4px 0; }\n  .pill { display: inline-block; padding: 2px 9px; border-radius: 4px;\n          font-size: 11px; font-weight: 600; letter-spacing: 0.3px; }\n  .pill.pass { background: rgba(62,201,122,0.15); color: var(--pass); }\n  .pill.fail { background: rgba(226,92,92,0.18);  color: var(--fail); }\n  .pill.warn { background: rgba(230,180,85,0.15); color: var(--warn); }\n  .pill.muted{ background: var(--panel2);          color: var(--muted); }\n  .tldr-box { background: var(--panel); border: 1px solid var(--border);\n              border-radius: 8px; padding: 18px 22px; margin: 18px 0 26px;\n              border-left: 3px solid var(--accent); }\n  .tldr-box h2 { border-top: 0; padding-top: 0; margin-top: 0; }\n  .footer { margin-top: 40px; padding-top: 18px; border-top: 1px solid var(--border);\n            color: var(--muted); font-size: 12px; text-align: center; }\n  .badge { display: inline-block; background: var(--panel2); padding: 4px 10px;\n           border-radius: 4px; font-size: 11px; color: var(--muted);\n           border: 1px solid var(--border); margin-right: 6px; }\n  .num-mono { font-family: ui-monospace, SF Mono, Menlo, monospace; }\n</style>\n</head>\n<body>\n<div class="wrap">\n\n<h1>hf-sandbox vs E2B — Scalability Comparison</h1>\n<div class="meta">\n  <span class="badge">2026-05-31</span>\n  <span class="badge">CPU-only</span>\n  <span class="badge">~$0.02 total spend</span>\n  <span class="badge">6 benchmarks · both providers</span>\n</div>\n\n<div class="tldr-box">\n<h2>TL;DR</h2>\n<table>\n  <tr><th>Dimension</th><th>E2B</th><th>hf-sandbox</th><th>Verdict</th></tr>\n  <tr><td>Cold boot (p50)</td><td class="num-mono">621 ms</td><td class="num-mono">23 162 ms</td><td><span class="pill pass">E2B ≈ 37× faster</span></td></tr>\n  <tr><td>Cold boot p99 @ N=20</td><td class="num-mono">1 966 ms</td><td class="num-mono">45 457 ms</td><td><span class="pill pass">E2B ≈ 23× faster</span></td></tr>\n  <tr><td>Warm exec throughput</td><td class="num-mono">3.6 ops/s</td><td class="num-mono">3.1 ops/s</td><td><span class="pill muted">tied (E2B 13%)</span></td></tr>\n  <tr><td>Warm exec p99</td><td class="num-mono">355 ms</td><td class="num-mono">416 ms</td><td><span class="pill muted">tied</span></td></tr>\n  <tr><td>10 MB write</td><td class="num-mono">3.52 MB/s</td><td class="num-mono">2.67 MB/s</td><td><span class="pill warn">E2B 32% faster</span></td></tr>\n  <tr><td>10 MB read</td><td class="num-mono">33.8 MB/s</td><td class="num-mono">4.79 MB/s</td><td><span class="pill pass">E2B ≈ 7× faster</span></td></tr>\n  <tr><td>Concurrent create @ N=20</td><td class="num-mono pass">20/20 (100%)</td><td class="num-mono pass">20/20 (100%)</td><td><span class="pill muted">tied</span></td></tr>\n  <tr><td>Concurrent create @ N=50</td><td class="num-mono pass">50/50 (100%)</td><td class="num-mono fail">29/50 (58%)</td><td><span class="pill fail">HF cliffs</span></td></tr>\n  <tr><td>Concurrent exec @ N=10</td><td class="num-mono pass">10/10 (100%)</td><td class="num-mono fail">4/10 (40%)</td><td><span class="pill fail">HF tunnel fails even @ low N</span></td></tr>\n  <tr><td>Single-sandbox stability (5 min)</td><td class="num-mono pass">100%</td><td class="num-mono pass">100%</td><td><span class="pill muted">tied</span></td></tr>\n</table>\n<p><strong>Bottom line:</strong> hf-sandbox is a functional Modal-style API on top of HF Jobs. It\'s fine for single-shot or small-fan-out workloads. <strong>It is not currently a drop-in replacement for E2B</strong> in any scenario that requires fast cold starts or ≥30 concurrent sandboxes — the Cloudflare-tunnel architecture caps the concurrent-create rate. For our existing eval sweeps (conc=100), <strong>E2B remains the right choice</strong> until hf-sandbox\'s tunnel stack is hardened.</p>\n</div>\n\n<h2>Setup</h2>\n<table>\n  <tr><th>Item</th><th>Value</th></tr>\n  <tr><td>hf-sandbox</td><td><code>huggingface/hf-sandbox</code> @ <code>hf-sandbox==0.1.1</code></td></tr>\n  <tr><td>E2B</td><td><code>e2b==2.x</code> Python SDK</td></tr>\n  <tr><td>Workload</td><td>Identical: <code>echo</code>, file write/read 1 KB → 10 MB, lifecycle</td></tr>\n  <tr><td>Image</td><td>E2B default template (Ubuntu 24.04 + Py 3.12) · HF <code>python:3.12-slim</code></td></tr>\n  <tr><td>Hardware tier</td><td>Both CPU-basic (1 vCPU / 512 MiB)</td></tr>\n  <tr><td>Pricing assumed</td><td>E2B $0.000014/s · HF Jobs $0.0000139/s (≈ parity)</td></tr>\n  <tr><td>Adapters</td><td>Uniform 5-method base (create / exec / read / write / terminate)</td></tr>\n</table>\n\n<h2>B01 — Cold boot latency</h2>\n<p>Time from <code>create()</code> to first successful <code>exec()</code>. Five cold runs each.</p>\n<table>\n  <tr><th>Metric</th><th>E2B (ms)</th><th>HF (ms)</th><th>Ratio</th></tr>\n  <tr><td>create p50</td><td class="num-mono">360</td><td class="num-mono">22 873</td><td><strong>63×</strong></td></tr>\n  <tr><td>first_exec p50</td><td class="num-mono">261</td><td class="num-mono">279</td><td>1.1×</td></tr>\n  <tr><td><strong>total (boot→ready) p50</strong></td><td class="num-mono pass"><strong>621</strong></td><td class="num-mono fail"><strong>23 162</strong></td><td><strong>37×</strong></td></tr>\n</table>\n<p><strong>Why:</strong> E2B uses snapshot-based templates that resume in ~1 s. hf-sandbox starts a fresh HF Job, installs a FastAPI RPC server, opens a Cloudflare tunnel, then becomes reachable — ~20-25 s end-to-end.</p>\n__IMG_B01__\n\n<h2>B02 — Single-sandbox exec throughput (warm)</h2>\n<p>100 sequential <code>echo</code> ops in one already-booted sandbox.</p>\n<table>\n  <tr><th>Provider</th><th>ops/s</th><th>exec p50</th><th>exec p99</th><th>exec max</th></tr>\n  <tr><td><strong>E2B</strong></td><td class="num-mono">3.6</td><td class="num-mono">270 ms</td><td class="num-mono">355 ms</td><td class="num-mono">453 ms</td></tr>\n  <tr><td><strong>HF</strong></td><td class="num-mono">3.1</td><td class="num-mono">311 ms</td><td class="num-mono">416 ms</td><td class="num-mono">819 ms</td></tr>\n</table>\n<p>Once warm, <strong>both are ≈3 ops/s, RPC-bound</strong> by HTTPS round-trip. The 13% gap is within tunnel/network noise. Effectively tied for sustained work.</p>\n\n<h2>B03 — File I/O throughput</h2>\n<p><code>write_file</code> + <code>read_file</code> at 1 KB / 64 KB / 1 MB / 10 MB.</p>\n<table>\n  <tr><th>Size</th><th>E2B write MB/s</th><th>HF write MB/s</th><th>E2B read MB/s</th><th>HF read MB/s</th></tr>\n  <tr><td>1 KB</td><td class="num-mono">0.00</td><td class="num-mono">0.00</td><td class="num-mono">0.00</td><td class="num-mono">0.00</td></tr>\n  <tr><td>64 KB</td><td class="num-mono">0.18</td><td class="num-mono">0.17</td><td class="num-mono">0.24</td><td class="num-mono">0.19</td></tr>\n  <tr><td>1 MB</td><td class="num-mono">0.97</td><td class="num-mono">1.01</td><td class="num-mono">3.86</td><td class="num-mono">1.16</td></tr>\n  <tr><td><strong>10 MB</strong></td><td class="num-mono"><strong>3.52</strong></td><td class="num-mono">2.67</td><td class="num-mono pass"><strong>33.84</strong></td><td class="num-mono">4.79</td></tr>\n</table>\n<p><strong>Two patterns:</strong></p>\n<ol>\n  <li>Small files are RPC-bound on both (single op ≈ 250-400 ms regardless of size &lt;100 KB).</li>\n  <li>Large reads on E2B exploit a streaming path (~34 MB/s) — HF tops out near 5 MB/s. Matters for pulling agent trajectories or trained-artifact downloads.</li>\n</ol>\n__IMG_B03__\n\n<h2>B04 — Concurrent create (the headline scalability number)</h2>\n<p>Fan out N parallel <code>create() → exec("echo ready") → terminate()</code> cycles.</p>\n<table>\n  <tr><th>N</th><th>E2B success</th><th>E2B wall</th><th>HF success</th><th>HF wall</th><th>HF errors</th></tr>\n  <tr><td>5</td><td class="num-mono pass">5/5 (100%)</td><td class="num-mono">2.1 s</td><td class="num-mono pass">5/5 (100%)</td><td class="num-mono">25.6 s</td><td>—</td></tr>\n  <tr><td>20</td><td class="num-mono pass">20/20 (100%)</td><td class="num-mono">2.2 s</td><td class="num-mono pass">20/20 (100%)</td><td class="num-mono">46.0 s</td><td>—</td></tr>\n  <tr><td><strong>50</strong></td><td class="num-mono pass"><strong>50/50 (100%)</strong></td><td class="num-mono"><strong>2.1 s</strong></td><td class="num-mono fail"><strong>29/50 (58%)</strong></td><td class="num-mono"><strong>88.1 s</strong></td><td><span class="pill fail">21 tunnel</span></td></tr>\n</table>\n<p><strong>E2B is essentially flat</strong> — 50 concurrent boots in the same wall time as 5 (2.1 s). Templates are cached and the platform absorbs the fan-out.</p>\n<p><strong>HF cliffs around N ≈ 30-50</strong> — Cloudflare-tunnel registration races / saturates, causing 21 of 50 sandboxes to die before they\'re reachable. Below N=20 it holds, but every successful boot still costs ~25-46 s wall-time.</p>\n__IMG_B04__\n\n<h2>B05 — Concurrent exec under load</h2>\n<p>N sandboxes × 20 sequential ops each, parallel workers.</p>\n<table>\n  <tr><th>Provider</th><th>N</th><th>Sandboxes ok</th><th>Ops total</th><th>Median worker p50</th><th>Worst worker p99</th><th>Errors</th></tr>\n  <tr><td>E2B</td><td>10</td><td class="num-mono pass">10/10</td><td class="num-mono">200 / 200</td><td class="num-mono">265 ms</td><td class="num-mono">548 ms</td><td>—</td></tr>\n  <tr><td>HF</td><td>10</td><td class="num-mono fail">4/10</td><td class="num-mono">80 / 86</td><td class="num-mono">275 ms</td><td class="num-mono">836 ms</td><td><span class="pill fail">6 tunnel</span></td></tr>\n</table>\n<p><strong>Same pattern as B04</strong> — for sandboxes that <em>do</em> boot, HF exec latency under load is on par with E2B (worker-level p50s match within ~5%). But <strong>even at N=10 HF lost 6/10 tunnels at create-time</strong>. The exec engine is fine; the boot engine is the bottleneck.</p>\n\n<h2>B06 — Long-running stability (5 min)</h2>\n<p>One sandbox, pinged every 20 s.</p>\n<table>\n  <tr><th>Provider</th><th>Pings ok</th><th>Survival rate</th><th>Notes</th></tr>\n  <tr><td>E2B</td><td class="num-mono">15/15</td><td class="pass"><strong>100%</strong></td><td>p50 ping ≈ 265 ms; one 914 ms blip</td></tr>\n  <tr><td>HF</td><td class="num-mono">15/15</td><td class="pass"><strong>100%</strong></td><td>p50 ping bimodal: ≈ 290 ms or ≈ 670 ms</td></tr>\n</table>\n<p>Once a tunnel is up, it stays up. The HF bimodality (extra ~400 ms on half the pings) likely reflects which Cloudflare edge each request hits, but it doesn\'t break correctness.</p>\n\n<h2>Cost (measured)</h2>\n<table>\n  <tr><th>Bench</th><th>E2B est.</th><th>HF est.</th></tr>\n  <tr><td>B01 (5 boots)</td><td class="num-mono">$0.0001</td><td class="num-mono">$0.0001</td></tr>\n  <tr><td>B02 (100 ops, 1 sandbox)</td><td class="num-mono">$0.0004</td><td class="num-mono">$0.0004</td></tr>\n  <tr><td>B03 (4 sizes × 3 reps)</td><td class="num-mono">$0.0008</td><td class="num-mono">$0.0008</td></tr>\n  <tr><td>B04 (N=5+20+50 cycles)</td><td class="num-mono">$0.0010</td><td class="num-mono">$0.0010</td></tr>\n  <tr><td>B05 (N=10 × 20 ops)</td><td class="num-mono">$0.0008</td><td class="num-mono">$0.0004</td></tr>\n  <tr><td>B06 (5-min)</td><td class="num-mono">$0.0043</td><td class="num-mono">$0.0043</td></tr>\n  <tr><td><strong>Total</strong></td><td class="num-mono"><strong>~$0.008</strong></td><td class="num-mono"><strong>~$0.007</strong></td></tr>\n</table>\n<p>Cost-per-sandbox-hour ends up nearly identical (~$0.05/hr at the cpu-basic tier). <strong>The differentiator isn\'t cost — it\'s reliability under load.</strong></p>\n\n<h2>When to use which</h2>\n<table>\n  <tr><th>Use case</th><th>Recommendation</th></tr>\n  <tr><td>One-off code execution (single user, single sandbox)</td><td>Either. <strong>HF</strong> wins on HF ecosystem fit</td></tr>\n  <tr><td>Agent eval at conc=100 (DABstep / data-agent-bench sweeps)</td><td class="pass"><strong>E2B</strong> — only option today</td></tr>\n  <tr><td>Long-running interactive coding agent</td><td class="pass"><strong>E2B</strong> — boot time (&lt; 1 s vs 23 s)</td></tr>\n  <tr><td>Bulk fan-out with template-able env</td><td class="pass"><strong>E2B</strong> — templates make conc ≥ 50 a non-issue</td></tr>\n  <tr><td>HF-native pipelines (training jobs that need scratch sandboxes)</td><td><strong>hf-sandbox</strong> fine at N ≤ 20</td></tr>\n</table>\n\n<h2>Caveats</h2>\n<ol>\n  <li><strong>hf-sandbox is v0.1.1</strong> — the API surface (5 methods) is minimal vs E2B\'s richer one (snapshots, MCP, volume mounts, network policies). Different scope, not strictly an E2B competitor.</li>\n  <li><strong>Free trycloudflare tunnels</strong> are best-effort. Production HF-Jobs deployments would presumably swap in a stable reverse proxy; until then the concurrent-create ceiling we measured is the real one.</li>\n  <li><strong>HF Job quota</strong> — our account has Pro tier; free tier limits are tighter.</li>\n  <li><strong>Only CPU-basic measured.</strong> GPU-tier behavior may differ.</li>\n  <li>Sample sizes are modest (n=5 for B01, n=10/20/50 for B04). Numbers are directional — the order-of-magnitude gaps in boot latency and N=50 failure rate are robust to that.</li>\n</ol>\n\n<h2>Reproducibility</h2>\n<pre><code>cd sandbox_comparision/\nuv venv --python 3.12 &amp;&amp; source .venv/bin/activate\nuv pip install "e2b" "hf-sandbox" "huggingface_hub" "python-dotenv" "matplotlib" "rich"\n# Auth via repo .env: E2B_API_KEY=… and HF_TOKEN=…\n\npython scripts/verify_setup.py\npython benchmarks/b01_boot_latency.py    --provider e2b --n 5\npython benchmarks/b04_concurrent_create.py --provider hf  --n 50\npython scripts/plot_results.py\npython scripts/build_html_report.py</code></pre>\n<p>Raw data: <code>results/raw/&lt;bench&gt;__&lt;provider&gt;.jsonl</code> (append-only). Charts: <code>results/charts/*.png</code>.</p>\n\n<div class="footer">\n  Generated from <code>sandbox_comparision/REPORT.md</code> · charts embedded as base64 ·\n  share this single HTML file freely.\n</div>\n</div>\n</body>\n</html>\n'

def main() -> None:
    html = HTML
    for key, fname, alt in [('__IMG_B01__', 'b01_boot_latency.png', 'B01 boot latency bar chart'), ('__IMG_B03__', 'b03_io.png', 'B03 IO throughput chart'), ('__IMG_B04__', 'b04_scaling.png', 'B04 concurrent-create scaling chart')]:
        p = CHARTS / fname
        if not p.exists():
            print(f'[warn] {p} missing — skipping {key}')
            html = html.replace(key, f'<p><em>chart missing: {fname}</em></p>')
            continue
        html = html.replace(key, img(p, alt))
    OUT.write_text(html)
    sz = OUT.stat().st_size / 1024
    print(f'[done] wrote {OUT}  ({sz:.0f} KB, self-contained)')
if __name__ == '__main__':
    main()
